MERGE INTO CONSULTAS FIN USING (SELECT '002518PartidasLibros_sub' INFORME ,TO_CLOB(q'[SELECT  OBSERVACIONES,FECHA,PARTIDA_DEBITO,PARTIDA_CREDITO
FROM    PARTIDAS_CONCILIATORIAS
WHERE   COMPANIA = s$compania$s
AND     ANO = s$ano$s
AND     MES_PARTIDA = s$mes$s
AND     CUENTA = 's$codCuenta$s']') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);